insert into public.recipes (id, user_id, title, category, image_url, images, cook_time_minutes, servings, difficulty, estimated_cost, notes, ingredients, steps, is_public, created_at) values
('aaaaaaaa-0000-4000-8000-000000000051', '22222222-2222-4222-8222-222222222222', 'Nasi Liwet Solo', 'Makanan', '/recipes/nasi-liwet.jpg', '["/recipes/nasi-liwet.jpg"]', 50, 4, 'Sedang', 30000, 'Gurihnya dari santan dan kaldu ayam; sajikan dengan areh.', '[{"name":"Beras","qty":500,"unit":"gram","secukupnya":false},{"name":"Santan","qty":400,"unit":"ml","secukupnya":false},{"name":"Kaldu ayam","qty":300,"unit":"ml","secukupnya":false},{"name":"Daun salam","qty":2,"unit":"lembar","secukupnya":false},{"name":"Serai","qty":1,"unit":"batang","secukupnya":false},{"name":"Garam","qty":null,"unit":null,"secukupnya":true}]', '["Cuci beras, tiriskan.","Rebus santan dan kaldu bersama daun salam dan serai.","Masukkan beras, masak hingga meresap.",{"text":"Kukus hingga matang dan pulen, sajikan dengan ayam suwir dan telur.","photos":["/recipes/nasi-liwet.jpg"]}]', true, now() - interval '1 days'),
('aaaaaaaa-0000-4000-8000-000000000052', '33333333-3333-4333-8333-333333333333', 'Ayam Penyet Sambal', 'Makanan', '/recipes/ayam-penyet.jpg', '["/recipes/ayam-penyet.jpg"]', 45, 2, 'Sedang', 25000, 'Ayam diungkep dulu supaya bumbu meresap sebelum digoreng.', '[{"name":"Ayam","qty":2,"unit":"potong","secukupnya":false},{"name":"Bawang putih","qty":4,"unit":"siung","secukupnya":false},{"name":"Kunyit","qty":2,"unit":"cm","secukupnya":false},{"name":"Cabai rawit","qty":12,"unit":"buah","secukupnya":false},{"name":"Tomat","qty":1,"unit":"buah","secukupnya":false},{"name":"Terasi","qty":1,"unit":"sdt","secukupnya":false}]', '["Ungkep ayam dengan bawang putih, kunyit, dan garam hingga empuk.",{"text":"Goreng ayam hingga keemasan.","photos":["/recipes/ayam-penyet.jpg"]},"Ulek cabai, tomat, terasi, dan garam jadi sambal.","Penyet ayam di atas sambal, sajikan dengan lalapan."]', true, now() - interval '2 days'),
('aaaaaaaa-0000-4000-8000-000000000053', '44444444-4444-4444-8444-444444444444', 'Semur Daging Kentang', 'Makanan', '/recipes/semur-daging.jpg', '["/recipes/semur-daging.jpg"]', 90, 5, 'Sedang', 55000, 'Kecap manis dan pala memberi rasa khas semur Betawi.', '[{"name":"Daging sapi","qty":500,"unit":"gram","secukupnya":false},{"name":"Kentang","qty":3,"unit":"buah","secukupnya":false},{"name":"Kecap manis","qty":5,"unit":"sdm","secukupnya":false},{"name":"Bawang merah","qty":6,"unit":"siung","secukupnya":false},{"name":"Bawang putih","qty":4,"unit":"siung","secukupnya":false},{"name":"Pala","qty":1,"unit":"sdt","secukupnya":false}]', '["Rebus daging hingga empuk, potong dadu.","Haluskan bawang, tumis hingga harum.","Masukkan daging, kecap, dan pala.","Tambahkan kentang, masak hingga bumbu meresap."]', true, now() - interval '3 days'),
('aaaaaaaa-0000-4000-8000-000000000054', '22222222-2222-4222-8222-222222222222', 'Sop Buntut Bening', 'Makanan', '/recipes/sop-buntut.jpg', '["/recipes/sop-buntut.jpg"]', 120, 4, 'Sulit', 70000, 'Rebus buntut cukup lama supaya empuk dan kaldu bening.', '[{"name":"Buntut sapi","qty":700,"unit":"gram","secukupnya":false},{"name":"Wortel","qty":2,"unit":"buah","secukupnya":false},{"name":"Kentang","qty":2,"unit":"buah","secukupnya":false},{"name":"Tomat","qty":1,"unit":"buah","secukupnya":false},{"name":"Bawang bombay","qty":1,"unit":"buah","secukupnya":false},{"name":"Pala","qty":1,"unit":"sdt","secukupnya":false}]', '["Rebus buntut hingga empuk dan berbusa, buang busanya.","Tumis bawang bombay, masukkan ke kaldu.","Tambahkan wortel dan kentang.","Bumbui pala, merica, dan garam, sajikan dengan bawang goreng."]', true, now() - interval '4 days'),
('aaaaaaaa-0000-4000-8000-000000000055', '33333333-3333-4333-8333-333333333333', 'Tongseng Kambing', 'Makanan', '/recipes/tongseng.jpg', '["/recipes/tongseng.jpg"]', 60, 4, 'Sedang', 60000, 'Tambahkan kol dan tomat di akhir supaya tetap segar.', '[{"name":"Daging kambing","qty":500,"unit":"gram","secukupnya":false},{"name":"Santan","qty":300,"unit":"ml","secukupnya":false},{"name":"Kol","qty":100,"unit":"gram","secukupnya":false},{"name":"Kecap manis","qty":3,"unit":"sdm","secukupnya":false},{"name":"Cabai rawit","qty":8,"unit":"buah","secukupnya":false},{"name":"Bawang merah","qty":6,"unit":"siung","secukupnya":false}]', '["Tumis bumbu halus hingga harum.","Masukkan daging kambing, aduk hingga berubah warna.","Tuang santan dan kecap, masak hingga empuk.","Masukkan kol, tomat, dan cabai, masak sebentar."]', true, now() - interval '5 days'),
('aaaaaaaa-0000-4000-8000-000000000056', '44444444-4444-4444-8444-444444444444', 'Gulai Kambing Padang', 'Makanan', '/recipes/gulai-kambing.jpg', '["/recipes/gulai-kambing.jpg"]', 100, 5, 'Sulit', 65000, 'Rempah lengkap kunci gulai yang kaya rasa.', '[{"name":"Daging kambing","qty":600,"unit":"gram","secukupnya":false},{"name":"Santan","qty":700,"unit":"ml","secukupnya":false},{"name":"Kunyit","qty":3,"unit":"cm","secukupnya":false},{"name":"Ketumbar","qty":1,"unit":"sdm","secukupnya":false},{"name":"Cabai merah","qty":8,"unit":"buah","secukupnya":false},{"name":"Serai","qty":2,"unit":"batang","secukupnya":false}]', '["Haluskan cabai, kunyit, dan ketumbar.","Tumis bumbu dengan serai hingga harum.","Masukkan daging, aduk rata.","Tuang santan, masak dengan api kecil hingga empuk dan kuah mengental."]', true, now() - interval '6 days'),
('aaaaaaaa-0000-4000-8000-000000000057', '22222222-2222-4222-8222-222222222222', 'Nasi Bakar Ayam', 'Makanan', '/recipes/nasi-bakar.jpg', '["/recipes/nasi-bakar.jpg"]', 40, 3, 'Sedang', 28000, 'Dibakar dalam daun pisang supaya wangi.', '[{"name":"Nasi putih","qty":3,"unit":"porsi","secukupnya":false},{"name":"Ayam suwir","qty":150,"unit":"gram","secukupnya":false},{"name":"Kemangi","qty":1,"unit":"ikat","secukupnya":false},{"name":"Cabai merah","qty":4,"unit":"buah","secukupnya":false},{"name":"Bawang merah","qty":4,"unit":"siung","secukupnya":false},{"name":"Daun pisang","qty":3,"unit":"lembar","secukupnya":false}]', '["Tumis bumbu halus, masukkan ayam suwir.","Campur nasi dengan tumisan dan kemangi.","Bungkus nasi dengan daun pisang.",{"text":"Bakar hingga daun harum dan kecoklatan.","photos":["/recipes/nasi-bakar.jpg"]}]', true, now() - interval '7 days'),
('aaaaaaaa-0000-4000-8000-000000000058', '33333333-3333-4333-8333-333333333333', 'Sate Padang', 'Makanan', '/recipes/sate-padang.jpg', '["/recipes/sate-padang.jpg"]', 60, 4, 'Sulit', 45000, 'Kuah kental berbumbu kunyit adalah ciri khasnya.', '[{"name":"Daging sapi","qty":500,"unit":"gram","secukupnya":false},{"name":"Tepung beras","qty":50,"unit":"gram","secukupnya":false},{"name":"Kunyit","qty":3,"unit":"cm","secukupnya":false},{"name":"Ketumbar","qty":1,"unit":"sdm","secukupnya":false},{"name":"Cabai merah","qty":6,"unit":"buah","secukupnya":false},{"name":"Tusuk sate","qty":20,"unit":"buah","secukupnya":false}]', '["Rebus daging dengan bumbu hingga empuk, potong dadu, tusuk.","Saring kaldu, kentalkan dengan tepung beras.","Bakar sate sebentar.","Siram sate dengan kuah kental, taburi bawang goreng."]', true, now() - interval '8 days'),
('aaaaaaaa-0000-4000-8000-000000000059', '44444444-4444-4444-8444-444444444444', 'Ayam Rica-Rica', 'Pedas', '/recipes/ayam-rica-rica.jpg', '["/recipes/ayam-rica-rica.jpg"]', 45, 4, 'Sedang', 35000, 'Pedasnya dari cabai rawit dan merah yang melimpah.', '[{"name":"Ayam","qty":1,"unit":"ekor","secukupnya":false},{"name":"Cabai merah","qty":10,"unit":"buah","secukupnya":false},{"name":"Cabai rawit","qty":15,"unit":"buah","secukupnya":false},{"name":"Bawang merah","qty":8,"unit":"siung","secukupnya":false},{"name":"Serai","qty":2,"unit":"batang","secukupnya":false},{"name":"Jeruk nipis","qty":1,"unit":"buah","secukupnya":false}]', '["Lumuri ayam dengan jeruk nipis dan garam.","Haluskan cabai dan bawang.","Tumis bumbu dengan serai hingga harum.","Masukkan ayam, masak hingga meresap dan matang."]', true, now() - interval '9 days'),
('aaaaaaaa-0000-4000-8000-000000000060', '22222222-2222-4222-8222-222222222222', 'Bebek Goreng Sambal Ijo', 'Makanan', '/recipes/bebek-goreng.jpg', '["/recipes/bebek-goreng.jpg"]', 90, 4, 'Sulit', 55000, 'Ungkep bebek lama supaya empuk dan tidak amis.', '[{"name":"Bebek","qty":1,"unit":"ekor","secukupnya":false},{"name":"Kunyit","qty":3,"unit":"cm","secukupnya":false},{"name":"Bawang putih","qty":5,"unit":"siung","secukupnya":false},{"name":"Lengkuas","qty":3,"unit":"cm","secukupnya":false},{"name":"Cabai hijau","qty":10,"unit":"buah","secukupnya":false},{"name":"Bawang merah","qty":5,"unit":"siung","secukupnya":false}]', '["Ungkep bebek dengan bumbu halus dan lengkuas hingga empuk.",{"text":"Goreng bebek hingga kering.","photos":["/recipes/bebek-goreng.jpg"]},"Ulek cabai hijau dan bawang, tumis jadi sambal ijo.","Sajikan bebek dengan sambal ijo dan lalapan."]', true, now() - interval '10 days'),
('aaaaaaaa-0000-4000-8000-000000000061', '33333333-3333-4333-8333-333333333333', 'Ayam Bakar Taliwang', 'Pedas', '/recipes/ayam-taliwang.jpg', '["/recipes/ayam-taliwang.jpg"]', 50, 3, 'Sedang', 40000, 'Khas Lombok, pedas manis dengan terasi.', '[{"name":"Ayam","qty":1,"unit":"ekor","secukupnya":false},{"name":"Cabai merah","qty":10,"unit":"buah","secukupnya":false},{"name":"Bawang merah","qty":6,"unit":"siung","secukupnya":false},{"name":"Terasi","qty":1,"unit":"sdt","secukupnya":false},{"name":"Gula merah","qty":30,"unit":"gram","secukupnya":false},{"name":"Jeruk limau","qty":2,"unit":"buah","secukupnya":false}]', '["Ungkep ayam dengan sebagian bumbu.","Haluskan cabai, bawang, terasi, gula merah.","Lumuri ayam dengan bumbu.",{"text":"Bakar ayam sambil diolesi bumbu hingga matang.","photos":["/recipes/ayam-taliwang.jpg"]}]', true, now() - interval '11 days'),
('aaaaaaaa-0000-4000-8000-000000000062', '44444444-4444-4444-8444-444444444444', 'Lontong Sayur Betawi', 'Sarapan', '/recipes/lontong-sayur.jpg', '["/recipes/lontong-sayur.jpg"]', 60, 4, 'Sedang', 25000, 'Kuah santan dengan labu siam dan telur.', '[{"name":"Lontong","qty":4,"unit":"buah","secukupnya":false},{"name":"Labu siam","qty":2,"unit":"buah","secukupnya":false},{"name":"Santan","qty":600,"unit":"ml","secukupnya":false},{"name":"Telur rebus","qty":4,"unit":"butir","secukupnya":false},{"name":"Cabai merah","qty":5,"unit":"buah","secukupnya":false},{"name":"Bawang merah","qty":6,"unit":"siung","secukupnya":false}]', '["Tumis bumbu halus hingga harum.","Masukkan labu siam, aduk rata.","Tuang santan, masak hingga labu empuk.","Sajikan lontong dengan kuah, telur, dan kerupuk."]', true, now() - interval '12 days'),
('aaaaaaaa-0000-4000-8000-000000000063', '22222222-2222-4222-8222-222222222222', 'Ketupat Sayur Pedas', 'Sarapan', '/recipes/ketupat-sayur.jpg', '["/recipes/ketupat-sayur.jpg"]', 50, 4, 'Sedang', 25000, 'Kuah pedas cocok untuk sarapan hangat.', '[{"name":"Ketupat","qty":4,"unit":"buah","secukupnya":false},{"name":"Nangka muda","qty":200,"unit":"gram","secukupnya":false},{"name":"Santan","qty":600,"unit":"ml","secukupnya":false},{"name":"Cabai merah","qty":8,"unit":"buah","secukupnya":false},{"name":"Bawang merah","qty":6,"unit":"siung","secukupnya":false},{"name":"Daun salam","qty":2,"unit":"lembar","secukupnya":false}]', '["Rebus nangka muda hingga empuk.","Tumis bumbu halus dengan daun salam.","Masukkan nangka dan santan, masak hingga meresap.","Sajikan ketupat dengan kuah sayur."]', true, now() - interval '13 days'),
('aaaaaaaa-0000-4000-8000-000000000064', '33333333-3333-4333-8333-333333333333', 'Nasi Jinggo Bali', 'Sarapan', '/recipes/nasi-jinggo.jpg', '["/recipes/nasi-jinggo.jpg"]', 40, 4, 'Mudah', 15000, 'Porsi kecil berbungkus daun, lauk sambal dan mie.', '[{"name":"Nasi putih","qty":4,"unit":"porsi","secukupnya":false},{"name":"Ayam suwir","qty":150,"unit":"gram","secukupnya":false},{"name":"Mie goreng","qty":100,"unit":"gram","secukupnya":false},{"name":"Sambal","qty":50,"unit":"gram","secukupnya":false},{"name":"Serundeng","qty":50,"unit":"gram","secukupnya":false},{"name":"Daun pisang","qty":4,"unit":"lembar","secukupnya":false}]', '["Siapkan nasi porsi kecil.","Tata ayam suwir, mie, sambal, dan serundeng.","Bungkus dengan daun pisang.","Sajikan bersama kerupuk."]', true, now() - interval '14 days'),
('aaaaaaaa-0000-4000-8000-000000000065', '44444444-4444-4444-8444-444444444444', 'Mie Aceh Goreng', 'Pedas', '/recipes/mie-aceh.jpg', '["/recipes/mie-aceh.jpg"]', 35, 2, 'Sedang', 25000, 'Bumbu kari dan cabai memberi rasa pedas gurih.', '[{"name":"Mie kuning","qty":250,"unit":"gram","secukupnya":false},{"name":"Udang","qty":100,"unit":"gram","secukupnya":false},{"name":"Daging","qty":100,"unit":"gram","secukupnya":false},{"name":"Cabai merah","qty":8,"unit":"buah","secukupnya":false},{"name":"Bumbu kari","qty":1,"unit":"sdm","secukupnya":false},{"name":"Tauge","qty":50,"unit":"gram","secukupnya":false}]', '["Haluskan cabai dan bawang, tumis dengan bumbu kari.","Masukkan daging dan udang, masak hingga matang.","Masukkan mie dan tauge.","Aduk rata dengan sedikit kaldu hingga meresap."]', true, now() - interval '15 days'),
('aaaaaaaa-0000-4000-8000-000000000066', '22222222-2222-4222-8222-222222222222', 'Dendeng Balado', 'Pedas', '/recipes/dendeng-balado.jpg', '["/recipes/dendeng-balado.jpg"]', 60, 4, 'Sedang', 50000, 'Daging tipis kering disiram sambal balado.', '[{"name":"Daging sapi","qty":500,"unit":"gram","secukupnya":false},{"name":"Cabai merah","qty":12,"unit":"buah","secukupnya":false},{"name":"Bawang merah","qty":6,"unit":"siung","secukupnya":false},{"name":"Bawang putih","qty":3,"unit":"siung","secukupnya":false},{"name":"Jeruk nipis","qty":1,"unit":"buah","secukupnya":false},{"name":"Garam","qty":null,"unit":null,"secukupnya":true}]', '["Iris tipis daging, ungkep dengan bumbu.","Goreng daging hingga kering.","Ulek cabai dan bawang, tumis jadi balado.","Masukkan dendeng, aduk rata dengan sambal."]', true, now() - interval '16 days'),
('aaaaaaaa-0000-4000-8000-000000000067', '33333333-3333-4333-8333-333333333333', 'Terong Balado', 'Pedas', '/recipes/terong-balado.jpg', '["/recipes/terong-balado.jpg"]', 25, 3, 'Mudah', 12000, 'Terong goreng disiram sambal merah pedas.', '[{"name":"Terong ungu","qty":3,"unit":"buah","secukupnya":false},{"name":"Cabai merah","qty":8,"unit":"buah","secukupnya":false},{"name":"Bawang merah","qty":5,"unit":"siung","secukupnya":false},{"name":"Tomat","qty":1,"unit":"buah","secukupnya":false},{"name":"Gula","qty":1,"unit":"sdt","secukupnya":false},{"name":"Garam","qty":null,"unit":null,"secukupnya":true}]', '["Potong terong, goreng hingga layu.","Ulek cabai, bawang, dan tomat.","Tumis sambal hingga matang berminyak.","Masukkan terong, aduk perlahan."]', true, now() - interval '17 days'),
('aaaaaaaa-0000-4000-8000-000000000068', '44444444-4444-4444-8444-444444444444', 'Telur Balado', 'Pedas', '/recipes/telur-balado.jpg', '["/recipes/telur-balado.jpg"]', 25, 4, 'Mudah', 15000, 'Telur rebus digoreng lalu dibalut sambal balado.', '[{"name":"Telur","qty":6,"unit":"butir","secukupnya":false},{"name":"Cabai merah","qty":10,"unit":"buah","secukupnya":false},{"name":"Bawang merah","qty":6,"unit":"siung","secukupnya":false},{"name":"Tomat","qty":1,"unit":"buah","secukupnya":false},{"name":"Gula merah","qty":1,"unit":"sdt","secukupnya":false},{"name":"Garam","qty":null,"unit":null,"secukupnya":true}]', '["Rebus dan kupas telur, goreng sebentar.","Ulek cabai, bawang, dan tomat.","Tumis sambal hingga matang.",{"text":"Masukkan telur, aduk hingga terbalut sambal.","photos":["/recipes/telur-balado.jpg"]}]', true, now() - interval '18 days'),
('aaaaaaaa-0000-4000-8000-000000000069', '22222222-2222-4222-8222-222222222222', 'Pastel Isi Sayur', 'Camilan', '/recipes/pastel.jpg', '["/recipes/pastel.jpg"]', 50, 10, 'Sedang', 18000, 'Kulit renyah berisi sayuran dan telur.', '[{"name":"Tepung terigu","qty":250,"unit":"gram","secukupnya":false},{"name":"Margarin","qty":50,"unit":"gram","secukupnya":false},{"name":"Wortel","qty":1,"unit":"buah","secukupnya":false},{"name":"Kentang","qty":1,"unit":"buah","secukupnya":false},{"name":"Telur rebus","qty":2,"unit":"butir","secukupnya":false},{"name":"Daun bawang","qty":2,"unit":"batang","secukupnya":false}]', '["Buat kulit dari terigu, margarin, dan air.","Tumis wortel dan kentang jadi isian.","Isi kulit, bentuk pastel, rekatkan pinggirnya.","Goreng hingga keemasan."]', true, now() - interval '19 days'),
('aaaaaaaa-0000-4000-8000-000000000070', '33333333-3333-4333-8333-333333333333', 'Combro Oncom', 'Camilan', '/recipes/combro.jpg', '["/recipes/combro.jpg"]', 40, 8, 'Mudah', 10000, 'Singkong parut isi oncom pedas.', '[{"name":"Singkong","qty":500,"unit":"gram","secukupnya":false},{"name":"Oncom","qty":150,"unit":"gram","secukupnya":false},{"name":"Cabai rawit","qty":6,"unit":"buah","secukupnya":false},{"name":"Bawang putih","qty":3,"unit":"siung","secukupnya":false},{"name":"Daun bawang","qty":2,"unit":"batang","secukupnya":false},{"name":"Garam","qty":null,"unit":null,"secukupnya":true}]', '["Parut singkong, peras airnya.","Tumis oncom dengan cabai jadi isian.","Bentuk singkong, isi oncom, bulatkan.","Goreng hingga kecoklatan."]', true, now() - interval '20 days'),
('aaaaaaaa-0000-4000-8000-000000000071', '44444444-4444-4444-8444-444444444444', 'Onde-Onde Wijen', 'Camilan', '/recipes/onde-onde.jpg', '["/recipes/onde-onde.jpg"]', 60, 12, 'Sedang', 15000, 'Bola tepung ketan isi kacang hijau bertabur wijen.', '[{"name":"Tepung ketan","qty":250,"unit":"gram","secukupnya":false},{"name":"Kacang hijau","qty":150,"unit":"gram","secukupnya":false},{"name":"Gula pasir","qty":100,"unit":"gram","secukupnya":false},{"name":"Wijen","qty":100,"unit":"gram","secukupnya":false},{"name":"Santan","qty":100,"unit":"ml","secukupnya":false},{"name":"Garam","qty":null,"unit":null,"secukupnya":true}]', '["Kukus dan haluskan kacang hijau dengan gula.","Uleni tepung ketan dengan santan hingga kalis.","Isi adonan dengan kacang, bulatkan, gulingkan di wijen.","Goreng hingga mengapung dan keemasan."]', true, now() - interval '21 days'),
('aaaaaaaa-0000-4000-8000-000000000072', '22222222-2222-4222-8222-222222222222', 'Cilok Bumbu Kacang', 'Camilan', '/recipes/cilok.jpg', '["/recipes/cilok.jpg"]', 40, 6, 'Mudah', 10000, 'Bola aci kenyal dengan saus kacang.', '[{"name":"Tepung tapioka","qty":250,"unit":"gram","secukupnya":false},{"name":"Tepung terigu","qty":100,"unit":"gram","secukupnya":false},{"name":"Bawang putih","qty":3,"unit":"siung","secukupnya":false},{"name":"Kacang tanah","qty":150,"unit":"gram","secukupnya":false},{"name":"Cabai rawit","qty":5,"unit":"buah","secukupnya":false},{"name":"Daun bawang","qty":2,"unit":"batang","secukupnya":false}]', '["Campur tapioka, terigu, dan bumbu dengan air panas.","Bentuk bulatan, rebus hingga mengapung.","Haluskan kacang dan cabai jadi saus.",{"text":"Sajikan cilok dengan saus kacang dan kecap.","photos":["/recipes/cilok.jpg"]}]', true, now() - interval '22 days'),
('aaaaaaaa-0000-4000-8000-000000000073', '33333333-3333-4333-8333-333333333333', 'Batagor Bandung', 'Camilan', '/recipes/batagor.jpg', '["/recipes/batagor.jpg"]', 45, 4, 'Sedang', 20000, 'Baso tahu goreng dengan bumbu kacang.', '[{"name":"Tahu","qty":6,"unit":"potong","secukupnya":false},{"name":"Ikan tenggiri","qty":200,"unit":"gram","secukupnya":false},{"name":"Tepung tapioka","qty":100,"unit":"gram","secukupnya":false},{"name":"Kacang tanah","qty":150,"unit":"gram","secukupnya":false},{"name":"Kulit pangsit","qty":10,"unit":"lembar","secukupnya":false},{"name":"Bawang putih","qty":3,"unit":"siung","secukupnya":false}]', '["Campur ikan, tapioka, dan bumbu jadi adonan.","Isi tahu dan kulit pangsit dengan adonan.","Goreng hingga keemasan.",{"text":"Sajikan dengan bumbu kacang, kecap, dan jeruk limau.","photos":["/recipes/batagor.jpg"]}]', true, now() - interval '23 days'),
('aaaaaaaa-0000-4000-8000-000000000074', '44444444-4444-4444-8444-444444444444', 'Otak-Otak Ikan', 'Camilan', '/recipes/otak-otak.jpg', '["/recipes/otak-otak.jpg"]', 45, 8, 'Sedang', 25000, 'Ikan halus berbumbu dibungkus daun lalu dibakar.', '[{"name":"Ikan tenggiri","qty":300,"unit":"gram","secukupnya":false},{"name":"Tepung sagu","qty":80,"unit":"gram","secukupnya":false},{"name":"Santan","qty":100,"unit":"ml","secukupnya":false},{"name":"Daun bawang","qty":2,"unit":"batang","secukupnya":false},{"name":"Bawang putih","qty":3,"unit":"siung","secukupnya":false},{"name":"Daun pisang","qty":8,"unit":"lembar","secukupnya":false}]', '["Haluskan ikan dengan bumbu dan santan.","Campur dengan tepung sagu dan daun bawang.","Bungkus dengan daun pisang.","Bakar hingga matang dan harum."]', true, now() - interval '24 days'),
('aaaaaaaa-0000-4000-8000-000000000075', '22222222-2222-4222-8222-222222222222', 'Kerak Telor Betawi', 'Camilan', '/recipes/kerak-telor.jpg', '["/recipes/kerak-telor.jpg"]', 30, 2, 'Sedang', 18000, 'Ketan dan telur dimasak di wajan tanpa minyak.', '[{"name":"Ketan putih","qty":100,"unit":"gram","secukupnya":false},{"name":"Telur","qty":2,"unit":"butir","secukupnya":false},{"name":"Ebi","qty":2,"unit":"sdm","secukupnya":false},{"name":"Serundeng","qty":50,"unit":"gram","secukupnya":false},{"name":"Bawang goreng","qty":2,"unit":"sdm","secukupnya":false},{"name":"Cabai","qty":null,"unit":null,"secukupnya":true}]', '["Rendam ketan, tiriskan.","Masak ketan di wajan panas, tambahkan telur.","Aduk dengan ebi dan bumbu.","Balik wajan di atas bara hingga kerak matang, taburi serundeng."]', true, now() - interval '25 days'),
('aaaaaaaa-0000-4000-8000-000000000076', '33333333-3333-4333-8333-333333333333', 'Lemper Ayam', 'Camilan', '/recipes/lemper.jpg', '["/recipes/lemper.jpg"]', 60, 10, 'Sedang', 20000, 'Ketan gurih isi ayam suwir, dibungkus daun.', '[{"name":"Ketan putih","qty":300,"unit":"gram","secukupnya":false},{"name":"Santan","qty":300,"unit":"ml","secukupnya":false},{"name":"Ayam suwir","qty":200,"unit":"gram","secukupnya":false},{"name":"Bawang merah","qty":4,"unit":"siung","secukupnya":false},{"name":"Serai","qty":1,"unit":"batang","secukupnya":false},{"name":"Daun pisang","qty":10,"unit":"lembar","secukupnya":false}]', '["Kukus ketan dengan santan hingga matang.","Tumis ayam suwir dengan bumbu.","Ambil ketan, isi ayam, padatkan.","Bungkus dengan daun pisang."]', true, now() - interval '26 days'),
('aaaaaaaa-0000-4000-8000-000000000077', '44444444-4444-4444-8444-444444444444', 'Nastar Selai Nanas', 'Kue & Dessert', '/recipes/nastar.jpg', '["/recipes/nastar.jpg"]', 90, 40, 'Sedang', 50000, 'Kue kering isi selai nanas, wajib saat lebaran.', '[{"name":"Tepung terigu","qty":300,"unit":"gram","secukupnya":false},{"name":"Mentega","qty":200,"unit":"gram","secukupnya":false},{"name":"Gula halus","qty":80,"unit":"gram","secukupnya":false},{"name":"Kuning telur","qty":3,"unit":"butir","secukupnya":false},{"name":"Nanas","qty":1,"unit":"buah","secukupnya":false},{"name":"Keju","qty":50,"unit":"gram","secukupnya":false}]', '["Masak nanas parut dengan gula jadi selai.","Kocok mentega, gula, dan kuning telur.","Masukkan terigu, uleni jadi adonan.",{"text":"Isi adonan dengan selai, bulatkan, panggang hingga matang.","photos":["/recipes/nastar.jpg"]}]', true, now() - interval '27 days'),
('aaaaaaaa-0000-4000-8000-000000000078', '22222222-2222-4222-8222-222222222222', 'Kastengel Keju', 'Kue & Dessert', '/recipes/kastengel.jpg', '["/recipes/kastengel.jpg"]', 80, 40, 'Sedang', 55000, 'Kue keju gurih yang renyah.', '[{"name":"Tepung terigu","qty":250,"unit":"gram","secukupnya":false},{"name":"Keju edam","qty":150,"unit":"gram","secukupnya":false},{"name":"Mentega","qty":150,"unit":"gram","secukupnya":false},{"name":"Kuning telur","qty":2,"unit":"butir","secukupnya":false},{"name":"Keju cheddar","qty":100,"unit":"gram","secukupnya":false},{"name":"Garam","qty":null,"unit":null,"secukupnya":true}]', '["Kocok mentega dan kuning telur.","Masukkan keju parut dan terigu, uleni.","Giling dan potong memanjang.","Olesi kuning telur, taburi keju, panggang hingga keemasan."]', true, now() - interval '28 days'),
('aaaaaaaa-0000-4000-8000-000000000079', '33333333-3333-4333-8333-333333333333', 'Putri Salju', 'Kue & Dessert', '/recipes/putri-salju.jpg', '["/recipes/putri-salju.jpg"]', 75, 40, 'Mudah', 40000, 'Kue bulan sabit bertabur gula halus.', '[{"name":"Tepung terigu","qty":250,"unit":"gram","secukupnya":false},{"name":"Mentega","qty":200,"unit":"gram","secukupnya":false},{"name":"Gula halus","qty":150,"unit":"gram","secukupnya":false},{"name":"Kacang mede","qty":100,"unit":"gram","secukupnya":false},{"name":"Kuning telur","qty":2,"unit":"butir","secukupnya":false},{"name":"Vanili","qty":1,"unit":"sdt","secukupnya":false}]', '["Kocok mentega dan gula.","Masukkan terigu dan kacang halus, uleni.","Bentuk bulan sabit, panggang.","Gulingkan di gula halus selagi hangat."]', true, now() - interval '1 days'),
('aaaaaaaa-0000-4000-8000-000000000080', '44444444-4444-4444-8444-444444444444', 'Bika Ambon Pandan', 'Kue & Dessert', '/recipes/bika-ambon.jpg', '["/recipes/bika-ambon.jpg"]', 120, 12, 'Sulit', 45000, 'Kue bersarang dengan aroma pandan.', '[{"name":"Tepung sagu","qty":200,"unit":"gram","secukupnya":false},{"name":"Santan","qty":400,"unit":"ml","secukupnya":false},{"name":"Telur","qty":6,"unit":"butir","secukupnya":false},{"name":"Gula pasir","qty":200,"unit":"gram","secukupnya":false},{"name":"Ragi instan","qty":1,"unit":"sdt","secukupnya":false},{"name":"Daun pandan","qty":3,"unit":"lembar","secukupnya":false}]', '["Rebus santan dengan pandan, dinginkan.","Campur telur, gula, sagu, dan ragi.","Diamkan adonan 2 jam hingga berbuih.","Panggang hingga bersarang dan matang."]', true, now() - interval '2 days'),
('aaaaaaaa-0000-4000-8000-000000000081', '22222222-2222-4222-8222-222222222222', 'Kue Lumpur Kentang', 'Kue & Dessert', '/recipes/kue-lumpur.jpg', '["/recipes/kue-lumpur.jpg"]', 50, 12, 'Mudah', 25000, 'Lembut dari kentang dan santan.', '[{"name":"Kentang","qty":250,"unit":"gram","secukupnya":false},{"name":"Santan","qty":400,"unit":"ml","secukupnya":false},{"name":"Telur","qty":3,"unit":"butir","secukupnya":false},{"name":"Gula pasir","qty":150,"unit":"gram","secukupnya":false},{"name":"Tepung terigu","qty":100,"unit":"gram","secukupnya":false},{"name":"Vanili","qty":1,"unit":"sdt","secukupnya":false}]', '["Kukus dan haluskan kentang.","Campur dengan santan, telur, gula, dan terigu.","Tuang ke cetakan panas.","Masak hingga matang, beri kismis di atasnya."]', true, now() - interval '3 days'),
('aaaaaaaa-0000-4000-8000-000000000082', '33333333-3333-4333-8333-333333333333', 'Bolu Kukus Mekar', 'Kue & Dessert', '/recipes/bolu-kukus.jpg', '["/recipes/bolu-kukus.jpg"]', 40, 12, 'Mudah', 20000, 'Mengembang cantik bila api kukusan besar.', '[{"name":"Tepung terigu","qty":200,"unit":"gram","secukupnya":false},{"name":"Gula pasir","qty":150,"unit":"gram","secukupnya":false},{"name":"Telur","qty":2,"unit":"butir","secukupnya":false},{"name":"Soda kue","qty":1,"unit":"sdt","secukupnya":false},{"name":"Santan","qty":150,"unit":"ml","secukupnya":false},{"name":"Pewarna","qty":null,"unit":null,"secukupnya":true}]', '["Kocok telur dan gula hingga mengembang.","Masukkan terigu dan santan bergantian.","Tuang ke cetakan penuh.","Kukus dengan api besar hingga mekar."]', true, now() - interval '4 days'),
('aaaaaaaa-0000-4000-8000-000000000083', '44444444-4444-4444-8444-444444444444', 'Pie Susu Bali', 'Kue & Dessert', '/recipes/pie-susu.jpg', '["/recipes/pie-susu.jpg"]', 60, 12, 'Sedang', 30000, 'Kulit renyah dengan isian susu lembut.', '[{"name":"Tepung terigu","qty":200,"unit":"gram","secukupnya":false},{"name":"Mentega","qty":100,"unit":"gram","secukupnya":false},{"name":"Gula halus","qty":50,"unit":"gram","secukupnya":false},{"name":"Susu kental manis","qty":100,"unit":"ml","secukupnya":false},{"name":"Kuning telur","qty":3,"unit":"butir","secukupnya":false},{"name":"Santan","qty":100,"unit":"ml","secukupnya":false}]', '["Buat kulit dari terigu, mentega, gula.","Cetak kulit di loyang pie.","Masak isian susu, telur, dan santan.","Tuang isian, panggang hingga set."]', true, now() - interval '5 days'),
('aaaaaaaa-0000-4000-8000-000000000084', '22222222-2222-4222-8222-222222222222', 'Es Doger', 'Minuman', '/recipes/es-doger.jpg', '["/recipes/es-doger.jpg"]', 20, 4, 'Mudah', 20000, 'Serutan es merah muda dengan aneka isian.', '[{"name":"Es serut","qty":null,"unit":null,"secukupnya":true},{"name":"Tape singkong","qty":100,"unit":"gram","secukupnya":false},{"name":"Ketan hitam","qty":100,"unit":"gram","secukupnya":false},{"name":"Santan","qty":300,"unit":"ml","secukupnya":false},{"name":"Sirup merah","qty":100,"unit":"ml","secukupnya":false},{"name":"Susu kental manis","qty":4,"unit":"sdm","secukupnya":false}]', '["Tata tape dan ketan hitam di gelas.","Tambahkan es serut.","Siram santan dan sirup merah.","Beri susu kental manis, sajikan segera."]', true, now() - interval '6 days'),
('aaaaaaaa-0000-4000-8000-000000000085', '33333333-3333-4333-8333-333333333333', 'Es Pisang Ijo', 'Minuman', '/recipes/es-pisang-ijo.jpg', '["/recipes/es-pisang-ijo.jpg"]', 45, 4, 'Sedang', 22000, 'Pisang berbalut kulit hijau dengan bubur dan sirup.', '[{"name":"Pisang raja","qty":4,"unit":"buah","secukupnya":false},{"name":"Tepung beras","qty":150,"unit":"gram","secukupnya":false},{"name":"Santan","qty":500,"unit":"ml","secukupnya":false},{"name":"Pasta pandan","qty":1,"unit":"sdt","secukupnya":false},{"name":"Sirup","qty":100,"unit":"ml","secukupnya":false},{"name":"Es batu","qty":null,"unit":null,"secukupnya":true}]', '["Buat kulit dari tepung beras, santan, dan pandan.","Bungkus pisang dengan kulit, kukus.","Masak bubur sumsum dari sisa adonan.","Potong pisang, siram bubur, sirup, dan es."]', true, now() - interval '7 days'),
('aaaaaaaa-0000-4000-8000-000000000086', '44444444-4444-4444-8444-444444444444', 'Bandrek Jahe', 'Minuman', '/recipes/bandrek.jpg', '["/recipes/bandrek.jpg"]', 20, 3, 'Mudah', 8000, 'Minuman jahe hangat khas Sunda.', '[{"name":"Jahe","qty":100,"unit":"gram","secukupnya":false},{"name":"Gula merah","qty":100,"unit":"gram","secukupnya":false},{"name":"Serai","qty":1,"unit":"batang","secukupnya":false},{"name":"Kayu manis","qty":1,"unit":"batang","secukupnya":false},{"name":"Cengkeh","qty":3,"unit":"buah","secukupnya":false},{"name":"Air","qty":700,"unit":"ml","secukupnya":false}]', '["Bakar dan geprek jahe.","Rebus air dengan jahe dan rempah.","Masukkan gula merah, aduk larut.","Saring, sajikan hangat."]', true, now() - interval '8 days'),
('aaaaaaaa-0000-4000-8000-000000000087', '22222222-2222-4222-8222-222222222222', 'Teh Tarik', 'Minuman', '/recipes/teh-tarik.jpg', '["/recipes/teh-tarik.jpg"]', 15, 2, 'Mudah', 8000, 'Ditarik supaya berbusa dan lembut.', '[{"name":"Teh hitam","qty":2,"unit":"sdm","secukupnya":false},{"name":"Susu kental manis","qty":4,"unit":"sdm","secukupnya":false},{"name":"Gula","qty":2,"unit":"sdm","secukupnya":false},{"name":"Air panas","qty":400,"unit":"ml","secukupnya":false}]', '["Seduh teh dengan air panas, saring.","Campur dengan susu dan gula.",{"text":"Tarik teh dari satu gelas ke gelas lain hingga berbusa.","photos":["/recipes/teh-tarik.jpg"]},"Sajikan hangat."]', true, now() - interval '9 days'),
('aaaaaaaa-0000-4000-8000-000000000088', '33333333-3333-4333-8333-333333333333', 'Jus Alpukat Coklat', 'Minuman', '/recipes/jus-alpukat.jpg', '["/recipes/jus-alpukat.jpg"]', 10, 2, 'Mudah', 15000, 'Kental dan creamy dengan saus coklat.', '[{"name":"Alpukat","qty":2,"unit":"buah","secukupnya":false},{"name":"Susu kental manis","qty":4,"unit":"sdm","secukupnya":false},{"name":"Coklat","qty":3,"unit":"sdm","secukupnya":false},{"name":"Gula","qty":1,"unit":"sdm","secukupnya":false},{"name":"Es batu","qty":null,"unit":null,"secukupnya":true}]', '["Keruk daging alpukat.","Blender dengan susu, gula, dan es.","Beri saus coklat di dinding gelas.","Tuang jus, sajikan dingin."]', true, now() - interval '10 days'),
('aaaaaaaa-0000-4000-8000-000000000089', '44444444-4444-4444-8444-444444444444', 'Es Teler', 'Minuman', '/recipes/es-teler.jpg', '["/recipes/es-teler.jpg"]', 20, 4, 'Mudah', 20000, 'Alpukat, kelapa muda, dan nangka dalam santan.', '[{"name":"Alpukat","qty":1,"unit":"buah","secukupnya":false},{"name":"Kelapa muda","qty":200,"unit":"gram","secukupnya":false},{"name":"Nangka","qty":100,"unit":"gram","secukupnya":false},{"name":"Santan","qty":300,"unit":"ml","secukupnya":false},{"name":"Susu kental manis","qty":4,"unit":"sdm","secukupnya":false},{"name":"Es serut","qty":null,"unit":null,"secukupnya":true}]', '["Potong alpukat, kelapa muda, dan nangka.","Tata di mangkuk.","Tambahkan es serut.","Siram santan dan susu kental manis."]', true, now() - interval '11 days'),
('aaaaaaaa-0000-4000-8000-000000000090', '22222222-2222-4222-8222-222222222222', 'Urap Sayur', 'Makanan Sehat', '/recipes/urap.jpg', '["/recipes/urap.jpg"]', 30, 4, 'Mudah', 15000, 'Aneka sayur rebus dengan kelapa parut berbumbu.', '[{"name":"Kacang panjang","qty":100,"unit":"gram","secukupnya":false},{"name":"Bayam","qty":1,"unit":"ikat","secukupnya":false},{"name":"Tauge","qty":100,"unit":"gram","secukupnya":false},{"name":"Kelapa parut","qty":150,"unit":"gram","secukupnya":false},{"name":"Cabai merah","qty":4,"unit":"buah","secukupnya":false},{"name":"Kencur","qty":2,"unit":"cm","secukupnya":false}]', '["Rebus semua sayuran, tiriskan.","Haluskan cabai, kencur, dan bumbu.","Campur bumbu dengan kelapa parut, kukus.","Aduk sayuran dengan kelapa berbumbu."]', true, now() - interval '12 days'),
('aaaaaaaa-0000-4000-8000-000000000091', '33333333-3333-4333-8333-333333333333', 'Karedok Sayur Mentah', 'Makanan Sehat', '/recipes/karedok.jpg', '["/recipes/karedok.jpg"]', 25, 3, 'Mudah', 15000, 'Sayuran mentah dengan bumbu kacang kencur.', '[{"name":"Kacang panjang","qty":100,"unit":"gram","secukupnya":false},{"name":"Timun","qty":1,"unit":"buah","secukupnya":false},{"name":"Tauge","qty":100,"unit":"gram","secukupnya":false},{"name":"Kol","qty":100,"unit":"gram","secukupnya":false},{"name":"Kacang tanah","qty":150,"unit":"gram","secukupnya":false},{"name":"Kencur","qty":2,"unit":"cm","secukupnya":false}]', '["Iris semua sayuran mentah.","Haluskan kacang, cabai, dan kencur.","Beri air asam dan gula merah.","Campur sayuran dengan bumbu kacang."]', true, now() - interval '13 days'),
('aaaaaaaa-0000-4000-8000-000000000092', '44444444-4444-4444-8444-444444444444', 'Sayur Lodeh', 'Makanan Sehat', '/recipes/sayur-lodeh.jpg', '["/recipes/sayur-lodeh.jpg"]', 40, 5, 'Mudah', 20000, 'Sayur berkuah santan dengan aneka isian.', '[{"name":"Labu siam","qty":1,"unit":"buah","secukupnya":false},{"name":"Terong","qty":1,"unit":"buah","secukupnya":false},{"name":"Kacang panjang","qty":100,"unit":"gram","secukupnya":false},{"name":"Santan","qty":600,"unit":"ml","secukupnya":false},{"name":"Cabai","qty":4,"unit":"buah","secukupnya":false},{"name":"Bawang merah","qty":5,"unit":"siung","secukupnya":false}]', '["Tumis bumbu halus hingga harum.","Masukkan sayuran yang keras dulu.","Tuang santan, masak perlahan.","Masukkan sisa sayuran, masak hingga matang."]', true, now() - interval '14 days'),
('aaaaaaaa-0000-4000-8000-000000000093', '22222222-2222-4222-8222-222222222222', 'Sayur Bening Bayam', 'Makanan Sehat', '/recipes/bening-bayam.jpg', '["/recipes/bening-bayam.jpg"]', 20, 4, 'Mudah', 10000, 'Sup bening segar rendah kalori.', '[{"name":"Bayam","qty":2,"unit":"ikat","secukupnya":false},{"name":"Jagung manis","qty":1,"unit":"buah","secukupnya":false},{"name":"Tomat","qty":1,"unit":"buah","secukupnya":false},{"name":"Bawang merah","qty":4,"unit":"siung","secukupnya":false},{"name":"Temu kunci","qty":2,"unit":"cm","secukupnya":false},{"name":"Gula","qty":1,"unit":"sdt","secukupnya":false}]', '["Rebus air dengan bawang dan temu kunci.","Masukkan jagung, masak hingga empuk.","Tambahkan bayam dan tomat.","Bumbui garam dan gula, masak sebentar."]', true, now() - interval '15 days'),
('aaaaaaaa-0000-4000-8000-000000000094', '33333333-3333-4333-8333-333333333333', 'Tahu Bacem', 'Vegetarian', '/recipes/tahu-bacem.jpg', '["/recipes/tahu-bacem.jpg"]', 45, 4, 'Mudah', 12000, 'Manis gurih dari gula merah dan kecap.', '[{"name":"Tahu","qty":8,"unit":"potong","secukupnya":false},{"name":"Gula merah","qty":50,"unit":"gram","secukupnya":false},{"name":"Kecap manis","qty":3,"unit":"sdm","secukupnya":false},{"name":"Bawang putih","qty":3,"unit":"siung","secukupnya":false},{"name":"Ketumbar","qty":1,"unit":"sdt","secukupnya":false},{"name":"Daun salam","qty":2,"unit":"lembar","secukupnya":false}]', '["Haluskan bawang dan ketumbar.","Rebus tahu dengan bumbu, gula merah, dan kecap.","Masak hingga air menyusut dan meresap.","Goreng sebentar sebelum disajikan."]', true, now() - interval '16 days'),
('aaaaaaaa-0000-4000-8000-000000000095', '44444444-4444-4444-8444-444444444444', 'Tempe Bacem', 'Vegetarian', '/recipes/tempe-bacem.jpg', '["/recipes/tempe-bacem.jpg"]', 45, 4, 'Mudah', 10000, 'Tempe manis legit, teman nasi hangat.', '[{"name":"Tempe","qty":300,"unit":"gram","secukupnya":false},{"name":"Gula merah","qty":50,"unit":"gram","secukupnya":false},{"name":"Kecap manis","qty":3,"unit":"sdm","secukupnya":false},{"name":"Bawang putih","qty":3,"unit":"siung","secukupnya":false},{"name":"Ketumbar","qty":1,"unit":"sdt","secukupnya":false},{"name":"Lengkuas","qty":2,"unit":"cm","secukupnya":false}]', '["Potong tempe, haluskan bumbu.","Rebus tempe dengan bumbu dan gula merah.","Masak hingga meresap.","Goreng hingga kecoklatan."]', true, now() - interval '17 days'),
('aaaaaaaa-0000-4000-8000-000000000096', '22222222-2222-4222-8222-222222222222', 'Kepiting Saus Padang', 'Seafood', '/recipes/kepiting-saus-padang.jpg', '["/recipes/kepiting-saus-padang.jpg"]', 50, 3, 'Sulit', 80000, 'Saus pedas manis membalut kepiting.', '[{"name":"Kepiting","qty":2,"unit":"ekor","secukupnya":false},{"name":"Saus tomat","qty":4,"unit":"sdm","secukupnya":false},{"name":"Cabai merah","qty":8,"unit":"buah","secukupnya":false},{"name":"Bawang putih","qty":4,"unit":"siung","secukupnya":false},{"name":"Telur","qty":1,"unit":"butir","secukupnya":false},{"name":"Saus tiram","qty":2,"unit":"sdm","secukupnya":false}]', '["Bersihkan dan rebus kepiting.","Haluskan cabai dan bawang, tumis.","Masukkan saus tomat, saus tiram, dan air.","Masukkan kepiting dan telur, aduk hingga meresap."]', true, now() - interval '18 days'),
('aaaaaaaa-0000-4000-8000-000000000097', '33333333-3333-4333-8333-333333333333', 'Kerang Saus Tiram', 'Seafood', '/recipes/kerang-saus.jpg', '["/recipes/kerang-saus.jpg"]', 30, 3, 'Sedang', 35000, 'Kerang segar tumis saus tiram pedas.', '[{"name":"Kerang hijau","qty":500,"unit":"gram","secukupnya":false},{"name":"Saus tiram","qty":3,"unit":"sdm","secukupnya":false},{"name":"Cabai rawit","qty":8,"unit":"buah","secukupnya":false},{"name":"Bawang putih","qty":4,"unit":"siung","secukupnya":false},{"name":"Jahe","qty":2,"unit":"cm","secukupnya":false},{"name":"Daun bawang","qty":2,"unit":"batang","secukupnya":false}]', '["Rebus kerang, buang yang tidak terbuka.","Tumis bawang, jahe, dan cabai.","Masukkan kerang dan saus tiram.","Aduk hingga meresap, taburi daun bawang."]', true, now() - interval '19 days'),
('aaaaaaaa-0000-4000-8000-000000000098', '44444444-4444-4444-8444-444444444444', 'Udang Goreng Tepung', 'Seafood', '/recipes/udang-goreng.jpg', '["/recipes/udang-goreng.jpg"]', 30, 3, 'Mudah', 40000, 'Renyah di luar, juicy di dalam.', '[{"name":"Udang","qty":400,"unit":"gram","secukupnya":false},{"name":"Tepung terigu","qty":150,"unit":"gram","secukupnya":false},{"name":"Tepung maizena","qty":50,"unit":"gram","secukupnya":false},{"name":"Bawang putih bubuk","qty":1,"unit":"sdt","secukupnya":false},{"name":"Telur","qty":1,"unit":"butir","secukupnya":false},{"name":"Garam","qty":null,"unit":null,"secukupnya":true}]', '["Kupas udang, sisakan ekor.","Celup udang ke telur, gulingkan ke tepung.","Goreng hingga keemasan dan renyah.",{"text":"Sajikan dengan saus sambal.","photos":["/recipes/udang-goreng.jpg"]}]', true, now() - interval '20 days'),
('aaaaaaaa-0000-4000-8000-000000000099', '22222222-2222-4222-8222-222222222222', 'Cumi Asam Manis', 'Seafood', '/recipes/cumi-asam-manis.jpg', '["/recipes/cumi-asam-manis.jpg"]', 30, 3, 'Sedang', 45000, 'Cumi kenyal dengan saus asam manis segar.', '[{"name":"Cumi","qty":400,"unit":"gram","secukupnya":false},{"name":"Saus tomat","qty":4,"unit":"sdm","secukupnya":false},{"name":"Nanas","qty":100,"unit":"gram","secukupnya":false},{"name":"Bawang bombay","qty":1,"unit":"buah","secukupnya":false},{"name":"Paprika","qty":1,"unit":"buah","secukupnya":false},{"name":"Jeruk nipis","qty":1,"unit":"buah","secukupnya":false}]', '["Bersihkan cumi, potong cincin, lumuri jeruk nipis.","Tumis bawang bombay hingga harum.","Masukkan saus tomat, nanas, dan paprika.","Masukkan cumi, masak sebentar agar tidak alot."]', true, now() - interval '21 days'),
('aaaaaaaa-0000-4000-8000-000000000100', '33333333-3333-4333-8333-333333333333', 'Pindang Ikan Serani', 'Seafood', '/recipes/pindang-ikan.jpg', '["/recipes/pindang-ikan.jpg"]', 40, 4, 'Sedang', 35000, 'Kuah bening asam segar berbumbu.', '[{"name":"Ikan","qty":500,"unit":"gram","secukupnya":false},{"name":"Belimbing wuluh","qty":5,"unit":"buah","secukupnya":false},{"name":"Cabai rawit","qty":8,"unit":"buah","secukupnya":false},{"name":"Kunyit","qty":2,"unit":"cm","secukupnya":false},{"name":"Serai","qty":1,"unit":"batang","secukupnya":false},{"name":"Tomat","qty":1,"unit":"buah","secukupnya":false}]', '["Bersihkan ikan, lumuri jeruk nipis.","Rebus air dengan bumbu dan serai.","Masukkan ikan dan belimbing wuluh.","Masak hingga ikan matang, koreksi rasa asam."]', true, now() - interval '22 days');
